class Solution:
    def findKthBit(self, n: int, k: int) -> str:
        def helper(n, k):
            if n == 1:
                return '0'
            length = (1 << n) - 1
            mid = (length + 1) // 2
            if k == mid:
                return '1'
            if k < mid:
                return helper(n - 1, k)
            bit = helper(n - 1, length - k + 1)
            return '1' if bit == '0' else '0'
        return helper(n, k)

