var findKthBit = function(n, k) {
    function helper(n, k) {
        if (n === 1) return '0';
        const length = (1 << n) - 1;
        const mid = Math.floor((length + 1) / 2);
        if (k === mid) return '1';
        if (k < mid) return helper(n - 1, k);
        const bit = helper(n - 1, length - k + 1);
        return bit === '0' ? '1' : '0';
    }
    return helper(n, k);
};
